--
-- Table structure for table `order`
--

DROP TABLE IF EXISTS `order`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `order` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '订单ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `order_no` varchar(50) NOT NULL COMMENT '订单编号',
  `amount` decimal(10,2) NOT NULL COMMENT '订单金额',
  `receiver_name` varchar(50) DEFAULT NULL COMMENT '收货人姓名',
  `receiver_phone` varchar(20) DEFAULT NULL COMMENT '收货人电话',
  `email` varchar(100) DEFAULT NULL COMMENT '联系邮箱',
  `receiver_province` varchar(50) DEFAULT NULL COMMENT '收货省份',
  `receiver_city` varchar(50) DEFAULT NULL COMMENT '收货城市',
  `receiver_district` varchar(50) DEFAULT NULL COMMENT '收货区县',
  `receiver_detail` varchar(255) DEFAULT NULL COMMENT '详细地址',
  `product_image` varchar(255) DEFAULT NULL COMMENT '商品图片URL',
  `diy_name` varchar(100) DEFAULT NULL COMMENT 'DIY作品名称',
  `description` varchar(1000) DEFAULT NULL COMMENT '手链组成描述（如材料顺序等）',
  `status` tinyint DEFAULT '0' COMMENT '状态：0待支付 1已支付 2已发货 3已完成 4退款中 5已退款',
  `pay_time` datetime DEFAULT NULL COMMENT '支付时间',
  `transaction_id` varchar(64) DEFAULT NULL COMMENT '微信支付交易号',
  `prepay_id` varchar(64) DEFAULT NULL COMMENT '微信预支付交易会话ID',
  `refund_amount` decimal(10,2) DEFAULT NULL COMMENT '退款金额',
  `refund_time` datetime DEFAULT NULL COMMENT '退款时间',
  `refund_reason` varchar(255) DEFAULT NULL COMMENT '退款原因',
  `remark` varchar(500) DEFAULT NULL COMMENT '订单备注',
  `refund_id` varchar(64) DEFAULT NULL COMMENT '微信退款单号',
  `delivery_time` datetime DEFAULT NULL COMMENT '发货时间',
  `tracking_number` varchar(100) DEFAULT NULL COMMENT '运单号（快递单号）',
  `complete_time` datetime DEFAULT NULL COMMENT '完成时间',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '下单时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `is_overseas` tinyint NOT NULL DEFAULT '0' COMMENT '是否海外版订单：0国内版，1海外版',
  `paypal_order_id` varchar(100) DEFAULT NULL COMMENT 'PayPal订单ID',
  `paypal_capture_id` varchar(100) DEFAULT NULL COMMENT 'PayPal捕获ID',
  PRIMARY KEY (`id`),
  UNIQUE KEY `order_no` (`order_no`),
  KEY `idx_transaction_id` (`transaction_id`),
  KEY `idx_update_time` (`update_time`),
  KEY `idx_order_is_overseas` (`is_overseas`),
  KEY `idx_order_paypal_order_id` (`paypal_order_id`)
) ENGINE=InnoDB AUTO_INCREMENT=164 DEFAULT CHARSET=utf8mb3 COMMENT='订单主表';
/*!40101 SET character_set_client = @saved_cs_client */;

