--
-- Table structure for table `paypal_webhook_event`
--

DROP TABLE IF EXISTS `paypal_webhook_event`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `paypal_webhook_event` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `event_id` varchar(100) NOT NULL COMMENT 'PayPal事件ID',
  `event_type` varchar(100) NOT NULL COMMENT '事件类型',
  `resource_id` varchar(100) DEFAULT NULL COMMENT '关联资源ID（如capture_id）',
  `payload` text COMMENT '原始事件JSON',
  `processed` tinyint(1) DEFAULT '0' COMMENT '是否已处理 0未处理 1已处理',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_event_id` (`event_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COMMENT='PayPal Webhook事件记录表（幂等）';
/*!40101 SET character_set_client = @saved_cs_client */;

